const rows = $input.all().map(r => r.json);
const week = new Date().toLocaleDateString('en-GB');
let totalRevenue = 0, totalLeads = 0;
rows.forEach(r => {
  totalRevenue += parseFloat(r['Revenue'] || 0);
  totalLeads   += parseInt(r['Leads'] || 0, 10);
});
const avgRevenue = rows.length ? (totalRevenue / rows.length).toFixed(2) : 0;
return [{
  json: {
    week,
    totalRevenue: totalRevenue.toFixed(2),
    totalLeads,
    avgDailyRevenue: avgRevenue,
    rowCount: rows.length,
    rows,
  }
}];
